const functions = require('firebase-functions');
const { Storage } = require('@google-cloud/storage');
const storage = new Storage();

exports.serveFile = functions.https.onRequest(async (req, res) => {
    const bucketName = req.query.bucket;
    const filePath = req.query.path;

    // Validate input
    if (!bucketName || !filePath) {
        return res.status(400).send('Bucket and path are required.');
    }

    // Allowlist for bucket names (example)
    const allowedBuckets = ['your-allowed-bucket-1', 'your-allowed-bucket-2'];
    if (!allowedBuckets.includes(bucketName)) {
        return res.status(403).send('Access to this bucket is forbidden.');
    }

    // Create a reference to the file
    const file = storage.bucket(bucketName).file(filePath);

    // Stream the file
    const readStream = file.createReadStream();

    readStream.on('error', (err) => {
        console.error('Error reading file:', err);
        return res.status(500).send('Error reading file.');
    });

    res.setHeader('Content-Disposition', `attachment; filename="${filePath.split('/').pop()}"`);
    readStream.pipe(res);
});